class DownloadRequest(BaseModel):
    url: str
    format: str = "mp4"
    quality: str = "1080p"

def quality_to_format(fmt, quality):
    if fmt == "mp3":
        return "bestaudio/best"
    q_map = {
        "720p":  "bestvideo[height<=720]+bestaudio/bestvideo[height<=720]/best",
        "1080p": "bestvideo[height<=1080]+bestaudio/bestvideo[height<=1080]/best",
        "4k":    "bestvideo[height<=2160]+bestaudio/bestvideo+bestaudio/best",
    }
    return q_map.get(quality, "bestvideo+bestaudio/best")

def get_cookies_file():
    """Écrit les cookies depuis la variable d'environnement dans un fichier temp."""
    cookies_content = os.environ.get("YOUTUBE_COOKIES", "")
    if not cookies_content:
        return None
    cookies_path = Path(tempfile.gettempdir()) / "yt_cookies.txt"
    cookies_path.write_text(cookies_content)
    return str(cookies_path)

def run_download(task_id, url, fmt, quality):
    task_dir = DOWNLOAD_DIR / task_id
    task_dir.mkdir(exist_ok=True)

    def progress_hook(d):
        if d["status"] == "downloading":
            total = d.get("total_bytes") or d.get("total_bytes_estimate", 0)
            downloaded = d.get("downloaded_bytes", 0)
            pct = int(downloaded / total * 85) if total else 10
            speed = d.get("_speed_str", "").strip()
            eta = d.get("_eta_str", "").strip()
            tasks[task_id].update({"progress": pct, "message": f"Téléchargement... {speed}" + (f" · ETA {eta}" if eta else "")})
        elif d["status"] == "finished":
            tasks[task_id].update({"progress": 90, "message": "Conversion en cours..."})

    ydl_opts = {
        "format": quality_to_format(fmt, quality),
        "outtmpl": str(task_dir / "%(title)s.%(ext)s"),
        "progress_hooks": [progress_hook],
        "quiet": True,
        "no_warnings": True,
        "merge_output_format": "mp4" if fmt == "mp4" else None,
    }
    if fmt == "mp3":
        ydl_opts["postprocessors"] = [{"key": "FFmpegExtractAudio", "preferredcodec": "mp3", "preferredquality": "192"}]

    # Ajouter les cookies si disponibles
    cookies_file = get_cookies_file()
    if cookies_file:
        ydl_opts["cookiefile"] = cookies_file

    try:
        tasks[task_id].update({"message": "Récupération des infos vidéo...", "progress": 5})
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            ydl.download([url])
        files = list(task_dir.glob("*"))
        if not files:
            raise Exception("Aucun fichier trouvé")
        fp = files[0]
        tasks[task_id].update({"status": "done", "progress": 100, "message": "Terminé !", "filepath": str(fp), "filename": fp.name})
    except Exception as e:
        tasks[task_id].update({"status": "error", "progress": 0, "message": f"Erreur : {e}"})

@app.get("/", response_class=HTMLResponse)
def index():
    return HTML

@app.post("/start")
def start(req: DownloadRequest):
    task_id = str(uuid.uuid4())
    tasks[task_id] = {"status": "running", "progress": 0, "message": "Démarrage...", "filepath": None, "filename": None}
    threading.Thread(target=run_download, args=(task_id, req.url, req.format, req.quality), daemon=True).start()
    return {"task_id": task_id}

@app.get("/progress/{task_id}")
async def progress(task_id: str):
    if task_id not in tasks:
        raise HTTPException(404)
    async def gen():
        while True:
            t = tasks.get(task_id, {})
            yield f"data: {json.dumps(t)}\n\n"
            if t.get("status") in ("done", "error"):
                break
            await asyncio.sleep(0.5)
    return StreamingResponse(gen(), media_type="text/event-stream", headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"})

@app.get("/file/{task_id}")
def get_file(task_id: str):
    t = tasks.get(task_id)
    if not t or t["status"] != "done":
        raise HTTPException(404)
    fp = Path(t["filepath"])
    return FileResponse(str(fp), filename=t["filename"], media_type="application/octet-stream")

@app.get("/health")
def health():
    return {"status": "ok"}

if __name__ == "__main__":
    import uvicorn
    port = int(os.environ.get("PORT", 8000))
    print(f"🐻 Nova Floup Download → http://localhost:{port}")
    uvicorn.run(app, host="0.0.0.0", port=port)
